// Models.ets
//
// Shared domain types and constant option lists for the 今天吃什么 app.
// Headless logic layer: no ArkUI decorators, safe to import from data/services/viewmodel.

// --- Enums expressed as string-literal unions + constant arrays ---

export type Mood =
  | '全部'
  | '想吃辣'
  | '清淡'
  | '治愈'
  | '重口味'
  | '健康';

export const MOOD_OPTIONS: Mood[] = ['全部', '想吃辣', '清淡', '治愈', '重口味', '健康'];

export type TimeBudget =
  | '全部'
  | '10分钟'
  | '半小时'
  | '不赶时间';

export const TIME_OPTIONS: TimeBudget[] = ['全部', '10分钟', '半小时', '不赶时间'];

export type MealType = '早餐' | '午餐' | '晚餐' | '加餐';
export const MEAL_TYPE_OPTIONS: MealType[] = ['早餐', '午餐', '晚餐', '加餐'];

export type IngredientCategory = '蔬菜' | '肉类' | '主食' | '蛋奶' | '调料' | '其他';
export const INGREDIENT_CATEGORY_OPTIONS: IngredientCategory[] =
  ['蔬菜', '肉类', '主食', '蛋奶', '调料', '其他'];

export type ShareTemplate = '暖橙' | '薄荷' | '莓果';
export const SHARE_TEMPLATE_OPTIONS: ShareTemplate[] = ['暖橙', '薄荷', '莓果'];

// --- Entities ---

export interface Dish {
  id: string;
  name: string;
  primaryMood: Mood; // excludes '全部'
  moodTags: Mood[]; // moods this dish satisfies; '全部' is a no-op placeholder
  timeBudget: TimeBudget; // excludes '全部'
  ingredients: string[]; // lower-cased display names, used for overlap matching
  emoji: string; // catalog-only decorative token, NOT rendered in final ArkTS UI
}

export interface Ingredient {
  id: string;
  name: string;
  category: IngredientCategory;
}

export interface CheckinRecord {
  id: string;
  mealType: MealType;
  dishName: string;
  note: string;
  photoUri: string; // empty string when absent (gallery pick only)
  timestamp: number; // ms since epoch
}

export interface ShareCard {
  id: string;
  dishName: string;
  date: number; // ms since epoch
  caption: string;
  template: ShareTemplate;
  sourceType: 'decide' | 'checkin';
}

// --- Filter bundle shared by decide wheel and fridge recommendation ---

export interface Filters {
  mood: Mood;
  time: TimeBudget;
}

export const DEFAULT_FILTERS: Filters = { mood: '全部', time: '全部' };

export function isAllMood(mood: Mood): boolean {
  return mood === '全部';
}

export function isAllTime(time: TimeBudget): boolean {
  return time === '全部';
}

// Normalize an arbitrary user-typed ingredient name for matching: trim + lowercase.
export function normalizeIngredientName(raw: string): string {
  return raw.trim().toLowerCase();
}

