// has more than one candidate, so the wheel yields a distinct suggestion each spin.
// Returns null only for an empty pool.
export function weightedPick(pool: Dish[], avoidId: string): Dish | null {
  if (pool.length === 0) {
    return null;
  }
  if (pool.length === 1) {
    return pool[0];
  }
  const eligible: Dish[] = [];
  for (const d of pool) {
    if (d.id !== avoidId) {
      eligible.push(d);
    }
