export function rankByIngredients(dishes: Dish[], ownedNames: string[]): Dish[] {
  const owned = new Set<string>();
  for (const n of ownedNames) {
    owned.add(n);
  }
  const scored = dishes.map((d: Dish) => ({ dish: d, score: overlapCount(d, owned) }));
  scored.sort((a: { dish: Dish; score: number }, b: { dish: Dish; score: number }) => {
