// StorageService.ets
//
// Preferences-backed persistence for ingredients, check-in records, and share cards.
// Headless logic: wraps @ohos.data.preferences, serializes entity arrays as JSON strings.
// AppViewModel calls init(context) at app start, then load/save helpers.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { CheckinRecord, Ingredient, ShareCard } from '../common/Models';

const PREF_NAME = 'eat_what_store';
const KEY_INGREDIENTS = 'ingredients_json';
const KEY_CHECKINS = 'checkins_json';
const KEY_SHARE_CARDS = 'share_cards_json';

const EMPTY_JSON = '[]';

export class StorageService {
  private prefs: preferences.Preferences | null = null;

  async init(context: common.Context): Promise<void> {
    this.prefs = await preferences.getPreferences(context, PREF_NAME);
  }

  private ensure(): preferences.Preferences {
    if (this.prefs === null) {
      throw new Error('StorageService not initialized; call init(context) first');
    }
    return this.prefs;
  }

  async loadIngredients(): Promise<Ingredient[]> {
    const raw = await this.ensure().get(KEY_INGREDIENTS, EMPTY_JSON);
    return this.parseList<Ingredient>(raw as string);
  }

  async saveIngredients(list: Ingredient[]): Promise<void> {
    await this.ensure().put(KEY_INGREDIENTS, JSON.stringify(list));
    await this.ensure().flush();
  }

  async loadCheckins(): Promise<CheckinRecord[]> {
    const raw = await this.ensure().get(KEY_CHECKINS, EMPTY_JSON);
    return this.parseList<CheckinRecord>(raw as string);
  }

  async saveCheckins(list: CheckinRecord[]): Promise<void> {
    await this.ensure().put(KEY_CHECKINS, JSON.stringify(list));
    await this.ensure().flush();
  }

  async loadShareCards(): Promise<ShareCard[]> {
    const raw = await this.ensure().get(KEY_SHARE_CARDS, EMPTY_JSON);
    return this.parseList<ShareCard>(raw as string);
  }

  async saveShareCards(list: ShareCard[]): Promise<void> {
    await this.ensure().put(KEY_SHARE_CARDS, JSON.stringify(list));
    await this.ensure().flush();
  }

  private parseList<T>(raw: string): T[] {
    if (!raw) {
      return [];
    }
    try {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        return parsed as T[];
      }
      return [];
    } catch (e) {
      return [];
    }
  }
}

