interface ScoredDish {
  dish: Dish;
  score: number;
}

// Rank dishes by ingredient overlap (desc). Stable tie-break on dish id for determinism.
// Returns a new sorted array; does not mutate input.
export function rankByIngredients(dishes: Dish[], ownedNames: string[]): Dish[] {
  const owned = new Set<string>();
  for (const n of ownedNames) {
    owned.add(n);
  }
  const scored: ScoredDish[] = dishes.map((d: Dish): ScoredDish => {
    return { dish: d, score: overlapCount(d, owned) };
  });
  scored.sort((a: ScoredDish, b: ScoredDish) => {
    if (a.score !== b.score) {
      return b.score - a.score;
    }
    if (a.dish.id < b.dish.id) {
      return -1;
    }
    if (a.dish.id > b.dish.id) {
      return 1;
    }
    return 0;
  });
  const out: Dish[] = [];
  for (const s of scored) {
    out.push(s.dish);
  }
  return out;
}

