//
// Static local dish catalog plus pure filtering / selection helpers.
// Headless logic: deterministic and side-effect-free (no ArkUI imports).
// Used by AppViewModel for wheel pool, filtering, and ingredient-overlap ranking.

import { Dish, Filters, Mood, TimeBudget, isAllMood, isAllTime } from '../common/Models';

// Static embedded dish catalog. No network dependency.
// ingredients are lower-cased display names for overlap matching.
