export function allDishes(): Dish[] {
  return DISH_CATALOG;
}

// Mood match: 全部 matches everything; otherwise dish must list the mood in moodTags
// or carry it as primaryMood.
export function dishMatchesMood(dish: Dish, mood: Mood): boolean {
  if (isAllMood(mood)) {
    return true;
  }
  if (dish.primaryMood === mood) {
    return true;
  }
  return dish.moodTags.indexOf(mood) >= 0;
}

export function dishMatchesTime(dish: Dish, time: TimeBudget): boolean {
  if (isAllTime(time)) {
    return true;
  }
  return dish.timeBudget === time;
}

export function filterByFilters(dishes: Dish[], filters: Filters): Dish[] {
  const out: Dish[] = [];
  for (const d of dishes) {
    if (dishMatchesMood(d, filters.mood) && dishMatchesTime(d, filters.time)) {
      out.push(d);
    }
  }
  return out;
}

export function filterByMood(dishes: Dish[], mood: Mood): Dish[] {
  const out: Dish[] = [];
  for (const d of dishes) {
    if (dishMatchesMood(d, mood)) {
      out.push(d);
    }
  }
  return out;
}

export function filterByTime(dishes: Dish[], time: TimeBudget): Dish[] {
  const out: Dish[] = [];
  for (const d of dishes) {
    if (dishMatchesTime(d, time)) {
      out.push(d);
    }
  }
  return out;
}

// Weighted random pick that avoids repeating the previous result when the pool
// has more than one candidate, so the wheel yields a distinct suggestion each spin.
// Returns null only for an empty pool.
export function weightedPick(pool: Dish[], avoidId: string): Dish | null {
  if (pool.length === 0) {
    return null;
  }
  if (pool.length === 1) {
    return pool[0];
  }
  const eligible: Dish[] = [];
  for (const d of pool) {
    if (d.id !== avoidId) {
      eligible.push(d);
    }
  }
  const candidates = eligible.length > 0 ? eligible : pool;
  const idx = Math.floor(Math.random() * candidates.length);
  return candidates[idx];
}

// Count how many of a dish's required ingredients are present in the user's fridge set.
export function overlapCount(dish: Dish, owned: Set<string>): number {
  let count = 0;
  for (const ing of dish.ingredients) {
    if (owned.has(ing)) {
      count += 1;
    }
  }
  return count;
}

// Rank dishes by ingredient overlap (desc). Stable tie-break on dish id for determinism.
// Returns a new sorted array; does not mutate input.
export function rankByIngredients(dishes: Dish[], ownedNames: string[]): Dish[] {
  const owned = new Set<string>();
  for (const n of ownedNames) {
    owned.add(n);
  }
  const scored = dishes.map((d: Dish) => ({ dish: d, score: overlapCount(d, owned) }));
  scored.sort((a: { dish: Dish; score: number }, b: { dish: Dish; score: number }) => {
    if (a.score !== b.score) {
      return b.score - a.score;
    }
    if (a.dish.id < b.dish.id) {
      return -1;
    }
    if (a.dish.id > b.dish.id) {
      return 1;
    }
    return 0;
  });
  const out: Dish[] = [];
  for (const s of scored) {
    out.push(s.dish);
  }
  return out;
}

