// AppViewModel.ets
//
// Central @Observed view-model for the 今天吃什么 app.
// Registered into AppStorage under key 'appViewModel'; pages bind via @StorageLink.
// Owns all observable state arrays and exposes the ui-behavior event methods.
// Delegates persistence to StorageService; array fields are reassigned (not mutated)
// so ArkUI @StorageLink observers re-render.

import { common } from '@kit.AbilityKit';
import {
  CheckinRecord,
  DEFAULT_FILTERS,
  Dish,
  Filters,
  Ingredient,
  IngredientCategory,
  MealType,
  Mood,
  ShareCard,
  ShareTemplate,
  TimeBudget,
  normalizeIngredientName,
} from '../common/Models';
import {
  DISH_CATALOG,
  filterByFilters,
  rankByIngredients,
  weightedPick,
} from '../data/DishCatalog';
import { StorageService } from '../services/StorageService';

const APP_STORAGE_KEY = 'appViewModel';
const TOAST_AUTO_CLEAR_MS = 2000;

function isSameCalendarDay(msA: number, msB: number): boolean {
  const da = new Date(msA);
  const db = new Date(msB);
  return da.getFullYear() === db.getFullYear() &&
    da.getMonth() === db.getMonth() &&
    da.getDate() === db.getDate();
}

@Observed
export class AppViewModel {
  // --- decide surface ---
  filters: Filters = { mood: DEFAULT_FILTERS.mood, time: DEFAULT_FILTERS.time };
  result: Dish | null = null;
  wheelSpinning: boolean = false;

  // --- fridge surface ---
  ingredients: Ingredient[] = [];
  recommendations: Dish[] = [];

  // --- check-in surface ---
  checkins: CheckinRecord[] = [];

  // --- share surface ---
  shareCards: ShareCard[] = [];
  preview: ShareCard | null = null;

  // --- cross-surface prefill ---
  pendingCheckinDish: string = '';

  // --- toast ---
  toastMessage: string = '';

  private storage: StorageService = new StorageService();
  private idCounter: number = 0;

  // ---- registration / lifecycle ----

  static ensureInAppStorage(context: common.Context): void {
    if (!AppStorage.has(APP_STORAGE_KEY)) {
      const vm = new AppViewModel();
      AppStorage.setOrCreate<AppViewModel>(APP_STORAGE_KEY, vm);
      vm.init(context);
    } else {
      const existing = AppStorage.get<AppViewModel>(APP_STORAGE_KEY);
      if (existing) {
        existing.init(context);
      }
    }
  }

  static get(): AppViewModel {
    const vm = AppStorage.get<AppViewModel>(APP_STORAGE_KEY);
    if (vm === undefined || vm === null) {
      // Fallback for environments without registration; not persisted.
      return new AppViewModel();
    }
    return vm;
  }

  async init(context: common.Context): Promise<void> {
    try {
      await this.storage.init(context);
      const [ingredients, checkins, cards] = await Promise.all([
        this.storage.loadIngredients(),
        this.storage.loadCheckins(),
        this.storage.loadShareCards(),
      ]);
      this.ingredients = ingredients;
      this.checkins = checkins;
      this.shareCards = cards;
    } catch (e) {
      // First-run or transient failure: keep empty in-memory state.
      this.ingredients = [];
      this.checkins = [];
      this.shareCards = [];
    }
  }

  // ---- computed helpers ----

  get todayCount(): number {
    const now = Date.now();
    let count = 0;
    for (const r of this.checkins) {
      if (isSameCalendarDay(r.timestamp, now)) {
        count += 1;
      }
    }
    return count;
  }

  private wheelPool(): Dish[] {
    return filterByFilters(DISH_CATALOG, this.filters);
  }

  private nextId(prefix: string): string {
    this.idCounter += 1;
    return `${prefix}-${Date.now()}-${this.idCounter}`;
  }

  // ---- decide / wheel events ----

  // Returns the picked Dish or null when the filtered pool is empty.
  // Visual integration owns the ~3s spin animation; this method performs the
  // logical selection and result assignment.
  spinWheel(): Dish | null {
    const pool = this.wheelPool();
    if (pool.length === 0) {
      this.showToast('没有符合条件的菜，试试调整筛选');
      return null;
    }
    const avoidId = this.result !== null ? this.result.id : '';
    const picked = weightedPick(pool, avoidId);
    if (picked === null) {
      this.showToast('没有符合条件的菜，试试调整筛选');
      return null;
    }
    this.wheelSpinning = true;
    // Logical result is set immediately; the wheel animation (visual phase) will
    // drive wheelSpinning back to false on settle. Kept synchronous here so the
    // result card and decide-result-name are bound as soon as the spin starts.
    this.result = picked;
    return picked;
  }

  setWheelSettled(): void {
    this.wheelSpinning = false;
  }

  // Pre-conditions for opening the filter sheet are visual; this commits the choice.
  applyFilters(mood: Mood, time: TimeBudget): void {
    this.filters = { mood: mood, time: time };
  }

  clearFilters(): void {
    this.filters = { mood: DEFAULT_FILTERS.mood, time: DEFAULT_FILTERS.time };
  }

  // use-result-checkin: prefill the add-checkin sheet with the wheel result name.
  prefillCheckinFromResult(): void {
    this.pendingCheckinDish = this.result !== null ? this.result.name : '';
  }

  consumePendingCheckinDish(): string {
    const value = this.pendingCheckinDish;
    this.pendingCheckinDish = '';
    return value;
  }

  // ---- fridge events ----

  addIngredient(rawName: string, category: IngredientCategory): boolean {
    const name = rawName.trim();
    if (name.length === 0) {
      this.showToast('请输入食材名称');
      return false;
    }
    const ingredient: Ingredient = {
      id: this.nextId('ing'),
      name: name,
      category: category,
    };
    this.ingredients = [ingredient, ...this.ingredients];
    this.persistIngredients();
    this.recomputeRecommendations();
    this.showToast('已添加食材');
    return true;
  }

  deleteIngredient(id: string): void {
    const next = this.ingredients.filter((item: Ingredient) => item.id !== id);
    this.ingredients = next;
    this.persistIngredients();
    this.recomputeRecommendations();
  }

  // recommend-by-ingredients
  recommend(): void {
    this.recomputeRecommendations();
  }

  private recomputeRecommendations(): void {
    const ownedNames: string[] = this.ingredients.map((i: Ingredient) => normalizeIngredientName(i.name));
    const candidates = filterByFilters(DISH_CATALOG, this.filters);
    const ranked = rankByIngredients(candidates, ownedNames);
    this.recommendations = ranked.filter((d: Dish) => {
      const owned = new Set<string>(ownedNames);
      let overlap = 0;
      for (const ing of d.ingredients) {
        if (owned.has(ing)) {
          overlap += 1;
        }
      }
      return overlap > 0;
    });
  }

  get hasIngredients(): boolean {
    return this.ingredients.length > 0;
  }

  get hasRecommendations(): boolean {
    return this.recommendations.length > 0;
  }

  // ---- check-in events ----

  addCheckin(mealType: MealType, rawDish: string, note: string, photoUri: string): boolean {
    const dishName = rawDish.trim();
    if (dishName.length === 0) {
      this.showToast('请输入菜名');
      return false;
    }
    const record: CheckinRecord = {
      id: this.nextId('ckn'),
      mealType: mealType,
      dishName: dishName,
      note: note.trim(),
      photoUri: photoUri,
      timestamp: Date.now(),
    };
    this.checkins = [record, ...this.checkins];
    this.persistCheckins();
    this.showToast('打卡成功');
    return true;
  }

  // ---- share events ----

  // open-share-preview-sheet: seed preview from latest decide result or most recent check-in.
  openSharePreview(template: ShareTemplate): void {
    let dishName = '';
    let sourceType: 'decide' | 'checkin' = 'decide';
    if (this.result !== null) {
      dishName = this.result.name;
      sourceType = 'decide';
    } else if (this.checkins.length > 0) {
      dishName = this.checkins[0].dishName;
      sourceType = 'checkin';
    }
    if (dishName.length === 0) {
      this.showToast('先去转盘选一道菜，或记录一餐再来分享');
      return;
    }
    this.preview = {
      id: this.nextId('shp'),
      dishName: dishName,
      date: Date.now(),
      caption: '',
      template: template,
      sourceType: sourceType,
    };
  }

  updatePreviewCaption(caption: string): void {
    if (this.preview === null) {
      return;
    }
    this.preview = {
      id: this.preview.id,
      dishName: this.preview.dishName,
      date: this.preview.date,
      caption: caption,
      template: this.preview.template,
      sourceType: this.preview.sourceType,
    };
  }

  // export-share-card: persist the previewed card. Real image rasterization is
  // deferred to visual integration; headless flow persists + toasts.
  exportShareCard(): void {
    if (this.preview === null) {
      return;
    }
    this.shareCards = [this.preview, ...this.shareCards];
    this.persistShareCards();
    this.showToast('已生成分享卡片');
    this.preview = null;
  }

  // system-share-card: persist the card, then signal the UI to invoke the system
  // share sheet. Returns the persisted card so the page can perform the share.
  systemShareCard(): ShareCard | null {
    if (this.preview === null) {
      return null;
    }
    this.shareCards = [this.preview, ...this.shareCards];
    this.persistShareCards();
    this.showToast('已分享');
    const shared = this.preview;
    this.preview = null;
    return shared;
  }

  // ---- toast ----

  showToast(message: string): void {
    this.toastMessage = message;
  }

  clearToast(): void {
    this.toastMessage = '';
  }

  get toastAutoClearMs(): number {
    return TOAST_AUTO_CLEAR_MS;
  }

  // ---- persistence ----

  private persistIngredients(): void {
    this.storage.saveIngredients(this.ingredients).catch(() => {});
  }

  private persistCheckins(): void {
    this.storage.saveCheckins(this.checkins).catch(() => {});
  }

  private persistShareCards(): void {
    this.storage.saveShareCards(this.shareCards).catch(() => {});
  }
}

